- **Install Redis**: `npm install redis`
- **Start Redis Server**: `redis-server`
- **Connect to Redis in Node.js**:
  ```javascript
  const redis = require('redis');
  const client = redis.createClient();
  ```
- **Set Cache with TTL (Time To Live)**:
  ```javascript
  client.setex('key', 3600, 'value'); // Cache for 1 hour
  ```
- **Get Cache**:
  ```javascript
  client.get('key', (err, reply) => {
    if (err) throw err;
    console.log(reply);
  });
  ```
- **Delete Cache**:
  ```javascript
  client.del('key');
  ```
- **Express Middleware for Caching**:
  ```javascript
  const express = require('express');
  const app = express();

  app.use((req, res, next) => {
    const key = req.originalUrl;
    client.get(key, (err, reply) => {
      if (err) throw err;
      if (reply) {
        res.send(reply);
      } else {
        res.sendResponse = res.send;
        res.send = function(body) {
          client.setex(key, 3600, body); // Cache for 1 hour
          res.sendResponse(body);
        };
        next();
      }
    });
  });

  app.get('/data', (req, res) => {
    // Fetch data from API or database
    res.send('Data fetched');
  });

  app.listen(3000, () => console.log('Server running on port 3000'));
  ```
- **Latest Redis Version**: Check [Redis official website](https://redis.io/download) for the latest version.
- **Key Config Options**:
  - `host`: Redis server host (default: '127.0.0.1')
  - `port`: Redis server port (default: 6379)
  - `password`: Redis password if authentication is enabled

